B.OD=new A.F(B.k,["Technical University in Dortmund","Technische Universit\xe4t Dortmund"],t.w)
B.Pd=new A.F(B.k,[u.A,"Studiengang: Wirtschaftsingenieurwesen (B.Sc.)\nProfil: Management elektrischer Systeme"],t.w)
