B.NA=new A.F(B.k,["Programming a Turtlebot with ROS in C++","Programmierung eines Turtlebots mit ROS in C++"],t.w)
B.Pr=new A.F(B.k,[u.aP,"Ich habe eine wissenschaftliche Arbeit zur Anwendung und Optimierung von Objekterkennung bei Nacht mittels Deep Learning (YOLOv8) in einer simulierten urbanen Umgebung aus der Perspektive eines fahrenden Autos verfasst."],t.w)
